"use strict";(self.webpackChunkfrontend=self.webpackChunkfrontend||[]).push([[2469],{2469:(e,a,n)=>{n.r(a),n.d(a,{default:()=>c});n(5043);var r=n(6400),i=n(2945),t=n(7338),s=n(6833),o=n(579);const c=()=>{const e=[{question:"What's the difference between a range, stove, and oven?",answer:"A range is the combined unit with stovetop burners and a built-in oven below. A stove typically refers to the cooktop/burner surface. An oven is the enclosed baking/roasting compartment. We repair all three."},{question:"How much does range repair cost?",answer:"Our diagnostic fee is $60 and applies toward the repair. Common range repairs (igniters, elements, sensors) typically run $150-$350 total. We provide written estimates before starting work."},{question:"Do you repair dual-fuel ranges?",answer:"Yes! Dual-fuel ranges (gas burners + electric oven) are our specialty. We're trained on both gas and electrical systems and can diagnose complex issues where the two systems interact."},{question:"Can you fix a range that's tripping my circuit breaker?",answer:"Absolutely. This usually indicates a short in the bake or broil element, faulty wiring, or a control board issue. We safely test all electrical paths to find and fix the fault."},{question:"What range brands do you service?",answer:"We service all residential range brands: GE, Whirlpool, Samsung, LG, Frigidaire, KitchenAid, Maytag, Bosch, as well as pro-style brands like Viking, Thermador, Wolf, and BlueStar."},{question:"How long does a typical range repair take?",answer:"Most range repairs are completed in 1-2 hours during a single visit. Complex issues (control boards, dual-fuel diagnostics) may require a parts order and follow-up visit at no extra trip charge."}],a={"@context":"https://schema.org","@type":"Service",serviceType:"Range\xa0Repair",provider:{"@type":"LocalBusiness",name:"FixitBay\xa0LLC",telephone:"(760) 543-5733"},areaServed:{"@type":"City",name:"San\xa0Francisco"}};return(0,t.a)()?(0,o.jsx)(i.A,{appliance:"Range",pageSlug:"range-repair",pageTitle:"Range\xa0Repair San\xa0Francisco | Gas & Electric | FixitBay\xa0LLC",metaDescription:"Expert range repair in San\xa0Francisco. Gas and electric ranges. $60 diagnostic applied to repair. 180-day warranty.",heroTitle:(0,o.jsxs)(o.Fragment,{children:["Expert Range",(0,o.jsx)("br",{}),"Repair in SF. Today."]}),heroImage:"/images/technicians/range-tech.jpg",heroImageAlt:"FixitBay technician next to a gas range in a San\xa0Francisco kitchen",heroImagePosition:"center center",techImage:"/images/technicians/range-tech.jpg",techImageAlt:"FixitBay technician next to a gas range in a San\xa0Francisco kitchen",heroSubtitle:"Gas, Electric & Dual-Fuel Ranges",issues:[{icon:"\ud83d\udd25",label:"Oven Cold"},{icon:"\ud83c\udf21\ufe0f",label:"Uneven Heat"},{icon:"\u26a1",label:"Won't Ignite"},{icon:"\ud83d\udd12",label:"Door Stuck"},{icon:"\ud83d\udcbb",label:"Error Code"},{icon:"\ud83d\udd27",label:"Dual-Fuel"}],faqs:e,schemaData:a}):(0,o.jsx)(r.A,{serviceSchema:a,appliance:"Range",pageTitle:"Range\xa0Repair San\xa0Francisco | Gas & Electric | FixitBay\xa0LLC",metaDescription:"Expert range repair in San\xa0Francisco. Gas and electric ranges. $60 diagnostic applied to repair. 180-day warranty.",heroImage:"/images/technicians/range-tech.jpg",heroImageAlt:"FixitBay technician next to a gas range in a San\xa0Francisco kitchen",commonProblems:[{title:"Oven Won't Heat But Burners Work",description:"When stovetop burners fire but the oven won't heat, the issue is typically a failed bake element, faulty igniter (gas ranges), or a broken temperature sensor. We isolate and fix the oven section."},{title:"Uneven Oven Temperatures",description:"Hot spots, underbaked centers, or burned edges indicate calibration drift, a failing convection fan, or worn heating elements. We test with precision instruments and restore even cooking."},{title:"Burner Ignition Failures",description:"Range burners that won't light or click endlessly have clogged igniter ports, failed spark modules, or gas valve issues. We clean, test, and replace components for reliable ignition."},{title:"Self-Clean Lock Stuck",description:"Door locks that jam during or after self-clean cycles prevent oven use. We safely release stuck locks and repair the latch mechanism, motor, or control board causing the issue."},{title:"Gas Range Won't Convert",description:"Ranges need orifice and regulator changes when switching between natural gas and propane. We perform safe, code-compliant conversions and test all burners and the oven afterward."},{title:"Digital Display Errors",description:"Error codes, blank displays, or unresponsive touchpads indicate control board or overlay failures. We diagnose electronic issues and repair or replace control components."},{title:"Oven Door Won't Close",description:"Bent hinges, broken springs, or misaligned door seals let heat escape, wasting energy and causing uneven cooking. We realign, replace, and adjust door hardware."},{title:"Dual-Fuel Range Issues",description:"Dual-fuel ranges combine gas burners with an electric oven, doubling potential failure points. We diagnose both systems \u2014 gas supply, igniters, elements, and electronic controls."}],faqData:e,serviceDescription:{title:"Professional Range\xa0Repair in San\xa0Francisco",paragraphs:["A kitchen range combines the convenience of a stovetop with a full oven in one unit \u2014 and when either section fails, it disrupts your entire cooking routine. FixitBay\xa0LLC provides expert range repair throughout San\xa0Francisco, the Peninsula, and Marin\xa0County. We service freestanding ranges, slide-in ranges, drop-in ranges, and professional-style units from every major manufacturer.","Our licensed technicians are trained to work on gas ranges, electric ranges, and dual-fuel models. We diagnose and repair igniters, heating elements, temperature sensors, convection fans, gas valves, control boards, and door mechanisms. San\xa0Francisco's diverse housing \u2014 from compact apartment kitchens to expansive chef's kitchens \u2014 means we encounter every range type and configuration. We bring the right tools and parts for each.","Every service call begins with our $60 diagnostic fee, which is credited in full toward your repair. We stock common parts for popular range brands and complete most repairs on the first visit. For specialty or pro-grade range parts, we source from authorized distributors and schedule a return visit at no additional trip charge. All repairs are backed by our 180-day warranty on parts and labor."]},comparisonTable:s.A.Range.comparisonTable,symptomsChecklist:s.A.Range.symptomsChecklist,diagnosisSteps:s.A.Range.diagnosisSteps,relatedLinks:[{href:"/oven-repair",label:"Oven\xa0Repair",desc:"Temperature issues, not heating, or timer problems"},{href:"/stove-repair",label:"Stove\xa0Repair",desc:"Burner issues, igniter problems, gas leaks"},{href:"/cooktop-repair",label:"Cooktop\xa0Repair",desc:"Electric, gas, or induction cooktop service"},{href:"/dishwasher-repair",label:"Dishwasher\xa0Repair",desc:"Not draining, leaking, or cleaning issues"}]})}}}]);
